class Solution:
    def maximalPathQuality(self, values, edges, maxTime):
        n = len(values)
        graph = [[] for _ in range(n)]
        for u, v, t in edges:
            graph[u].append((v, t))
            graph[v].append((u, t))
        best = values[0]
        stack = [(0, maxTime, values[0], frozenset({0}))]
        while stack:
            node, time_left, quality, visited = stack.pop()
            if node == 0:
                best = max(best, quality)
            for nxt, t in graph[node]:
                if t <= time_left:
                    if nxt in visited:
                        stack.append((nxt, time_left - t, quality, visited))
                    else:
                        stack.append((nxt, time_left - t, quality + values[nxt], visited | {nxt}))
        return best

