class Solution:
    def maximalPathQuality(self, values, edges, maxTime):
        n = len(values)
        graph = [[] for _ in range(n)]
        for u, v, t in edges:
            graph[u].append((v, t))
            graph[v].append((u, t))
        visited = [0] * n
        visited[0] = 1
        best = values[0]

        def dfs(node, time_left, quality):
            nonlocal best
            if node == 0:
                best = max(best, quality)
            for nxt, t in graph[node]:
                if t <= time_left:
                    first_visit = visited[nxt] == 0
                    visited[nxt] += 1
                    dfs(nxt, time_left - t, quality + (values[nxt] if first_visit else 0))
                    visited[nxt] -= 1

        dfs(0, maxTime, values[0])
        return best

