var maximalPathQuality = function(values, edges, maxTime) {
    const n = values.length;
    const graph = Array.from({ length: n }, () => []);
    for (const [u, v, t] of edges) {
        graph[u].push([v, t]);
        graph[v].push([u, t]);
    }
    const visited = new Array(n).fill(0);
    visited[0] = 1;
    let best = values[0];

    function dfs(node, timeLeft, quality) {
        if (node === 0) best = Math.max(best, quality);
        for (const [nxt, t] of graph[node]) {
            if (t <= timeLeft) {
                const firstVisit = visited[nxt] === 0;
                visited[nxt]++;
                dfs(nxt, timeLeft - t, quality + (firstVisit ? values[nxt] : 0));
                visited[nxt]--;
            }
        }
    }

    dfs(0, maxTime, values[0]);
    return best;
};
